def detect_plagiarism(source: str, suspect: str, k: int) -> list:
    if k <= 0 or k > len(suspect) or k > len(source):
        return []

    def kmp_search(text, pattern):
        """Returns True if pattern appears as a substring in text using KMP."""
        n, m = len(text), len(pattern)
        if m == 0:
            return True
        if m > n:
            return False

        # Build failure (partial match) table
        fail = [0] * m
        j = 0
        for i in range(1, m):
            while j > 0 and pattern[j] != pattern[i]:
                j = fail[j - 1]
            if pattern[j] == pattern[i]:
                j += 1
            fail[i] = j

        # KMP search
        j = 0
        for i in range(n):
            while j > 0 and pattern[j] != text[i]:
                j = fail[j - 1]
            if pattern[j] == text[i]:
                j += 1
            if j == m:
                return True
        return False

    result = []
    seen = {}  # Cache: k-gram string -> bool (found in source)
    for i in range(len(suspect) - k + 1):
        gram = suspect[i:i + k]
        if gram not in seen:
            seen[gram] = kmp_search(source, gram)
        if seen[gram]:
            result.append(i)

    return result

