import unittest

class TestPlagiarismDetector(unittest.TestCase):

    def test_basic_overlap(self):
        result = detect_plagiarism("the quick brown fox", "a quick brown dog", 5)
        self.assertEqual(result, [1, 2, 3, 4, 5, 6, 7, 8, 9])

    def test_no_match(self):
        result = detect_plagiarism("hello world", "foobar", 3)
        self.assertEqual(result, [])

    def test_all_match(self):
        result = detect_plagiarism("abcabc", "abcab", 3)
        self.assertEqual(result, [0, 1, 2])

    def test_hidden_single_char_k(self):
        result = detect_plagiarism("abc", "bcd", 1)
        self.assertEqual(result, [0, 1])

    def test_hidden_k_exceeds_suspect(self):
        result = detect_plagiarism("abcdef", "ab", 5)
        self.assertEqual(result, [])

    def test_hidden_k_exceeds_source(self):
        result = detect_plagiarism("ab", "abcde", 5)
        self.assertEqual(result, [])

    def test_hidden_identical_strings(self):
        result = detect_plagiarism("abcdef", "abcdef", 3)
        self.assertEqual(result, [0, 1, 2, 3])

    def test_hidden_repeated_chars_partial(self):
        result = detect_plagiarism("aaaaaa", "aaabaa", 3)
        self.assertEqual(result, [0])

    def test_hidden_tricky_kmp_pattern(self):
        result = detect_plagiarism("aabaabaab", "aabaaab", 3)
        self.assertEqual(result, [0, 1, 2, 4])

    def test_hidden_single_char_match(self):
        result = detect_plagiarism("a", "a", 1)
        self.assertEqual(result, [0])

    def test_hidden_k_zero(self):
        result = detect_plagiarism("abc", "abc", 0)
        self.assertEqual(result, [])

    def test_hidden_large_input(self):
        source = "ab" * 5000
        suspect = "ab" * 5000
        k = 4
        result = detect_plagiarism(source, suspect, k)
        self.assertEqual(result, list(range(10000 - 4 + 1)))

if __name__ == '__main__':
    unittest.main()
